+/// `tkill(tid, sig)` — send signal to thread (deprecated, use tgkill).
+#[inline]
+#[allow(unsafe_code)]
+pub fn sys_tkill(tid: i32, sig: i32) -> Result<(), i32> {
+    let ret = unsafe { raw::syscall2(SYS_TKILL, tid as usize, sig as usize) };
+    syscall_result(ret).map(|_| ())
